17	#include "api/core.h"
18	#include "api/thread.h"
19	#include "arm64/thread_info.h"
20	#include "arm/thread_info.h"
21	#include "base/utils.h"
22	#include "common/exception.h"
23	#include "common/bit.h"
24	#include <string.h>
25	#include <iomanip>
26	#include <iostream>
27	
28	int main(int argc, const char* argv[]) {
29	    std::cout << CoreApi::Load(argv[1], nullptr) << std::endl;
30	    std::cout << CoreApi::GetMachineName() << std::endl;
31	
32	    CoreApi::Write(0x12c00018, 0xdeaddeaddeaddeadUL);
33	    CoreApi::Write(0x6f718f2000, 0xdeaddeaddeaddeadUL);
34	
35	    uint8_t value[0x100];
36	    memset(value, 0x0, sizeof(value));
37	    uint64_t beginaddr = 0x12c00018;
38	    CoreApi::Read(beginaddr, sizeof(value), value);
39	    int count = sizeof(value) / sizeof(uint64_t);
40	    for (int index = 0; index < count; index += 2) {
41	        std::cout << std::hex << (beginaddr + index * 0x8) << ": "
42	                  << std::setw(16) << std::setfill('0') << reinterpret_cast<uint64_t *>(value)[index] << "  "
43	                  << std::setw(16) << std::setfill('0') << reinterpret_cast<uint64_t *>(value)[index + 1] << "  "
44	                  << Utils::ConvertAscii(reinterpret_cast<uint64_t *>(value)[index], 8)
45	                  << Utils::ConvertAscii(reinterpret_cast<uint64_t *>(value)[index + 1], 8) << std::endl;
46	    }
47	
48	    std::cout << std::endl;
49	    memset(value, 0x0, sizeof(value));
50	    CoreApi::Read(beginaddr, sizeof(value), value, OPT_READ_MMAP);
51	    for (int index = 0; index < count; index += 2) {
52	        std::cout << std::hex << (beginaddr + index * 0x8) << ": "
53	                  << std::setw(16) << std::setfill('0') << reinterpret_cast<uint64_t *>(value)[index] << "  "
54	                  << std::setw(16) << std::setfill('0') << reinterpret_cast<uint64_t *>(value)[index + 1] << "  "
55	                  << Utils::ConvertAscii(reinterpret_cast<uint64_t *>(value)[index], 8)
56	                  << Utils::ConvertAscii(reinterpret_cast<uint64_t *>(value)[index + 1], 8) << std::endl;
57	    }
58	
59	    std::cout << std::hex << *(uint64_t *)CoreApi::GetReal(0x12c00018) << std::endl;
60	    std::cout << std::hex << CoreApi::GetVirtual(CoreApi::GetReal(0x12c00018)) << std::endl;
61	    try {
62	        std::cout << std::hex << *(uint64_t *)CoreApi::GetReal(0x0000007e19f14100UL) << std::endl;
63	    } catch (InvalidAddressException e) {
64	        std::cout << e.what() << std::endl;
65	    }
66	    std::cout << std::hex << RoundUp(0x1994, 0x1000) << std::endl;
67	    std::cout << std::hex << RoundDown(0x1994, 0x1000) << std::endl;
68	    std::cout << std::hex << CoreApi::FindAuxv(AT_EXECFN) << std::endl;
69	
70	    ThreadApi* thread = CoreApi::FindThread(1745);
71	    if (thread && !strcmp(CoreApi::GetMachineName(), "arm64")) {
72	        arm64::ThreadInfo* info = reinterpret_cast<arm64::ThreadInfo *>(thread);
73	        std::cout << std::hex << info->reg.pc << std::endl;
74	    }
75	
76	    ThreadApi* thread1 = CoreApi::FindThread(7836);
77	    std::cout << "thread1 " << thread1 << std::endl;
78	    if (thread1 && !strcmp(CoreApi::GetMachineName(), "arm")) {
79	        arm::ThreadInfo* info = reinterpret_cast<arm::ThreadInfo *>(thread1);
80	        std::cout << std::hex << info->reg.pc << std::endl;
81	    }
82	
83	    // std::cout << std::hex << CoreApi::GetDebug() << std::endl;
84	#ifdef __ANDROID__
85	    CoreApi::ExecFile("/system");
86	    CoreApi::SysRoot("/system:/vendor");
87	#endif
88	    // CoreApi::DumpFile();
89	    // CoreApi::DumpLinkMap();
90	    // CoreApi::UnLoad();
91	    return 0;
92	}
