17	#include <chrono>
18	#include <iostream>
19	
20	using namespace std::chrono;
21	
22	int main() {
23	    auto starttime = system_clock::now();
24		char *line;
25		size_t length = 0;
26	    while (getline(&line, &length, stdin) > 0) {}
27	    duration<double> diff = system_clock::now()- starttime;
28	    std::cout << "time: " << diff.count() << " (seconds)" << std::endl;
29	    return 0;
30	}
